async function loadMountains(){
  try{
    const res=await fetch('data/mountains.json',{cache:'no-store'});
    if(!res.ok)throw new Error('mountains json');
    const data=await res.json();
    if(Array.isArray(data)&&data.length)mountains=data;
  }catch(e){
    console.warn('Using embedded fallback mountain data',e);
  }
}
const $=(s,r=document)=>r.querySelector(s);const $$=(s,r=document)=>Array.from(r.querySelectorAll(s));
function toast(msg){let el=$('.toast');if(!el){el=document.createElement('div');el.className='toast';document.body.appendChild(el)}el.textContent=msg;el.classList.add('show');setTimeout(()=>el.classList.remove('show'),1800)}
function getSaved(){return JSON.parse(localStorage.getItem('dmc.saved')||'[]')}function setSaved(v){localStorage.setItem('dmc.saved',JSON.stringify(v));updateSavedCounts()}function isSaved(id){return getSaved().includes(id)}function toggleSave(id){const s=getSaved();const next=s.includes(id)?s.filter(x=>x!==id):[...s,id];setSaved(next);toast(next.includes(id)?'저장했습니다':'저장을 해제했습니다');renderDynamic()}function updateSavedCounts(){document.querySelectorAll('[data-saved-count]').forEach(el=>el.textContent=getSaved().length)}
function escapeHtml(value){return String(value??'').replace(/[&<>"']/g,ch=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[ch]))}
function mountainImage(m){return m.imageThumb||m.image||'assets/hero.jpg'}
function imageCredit(m){if(!m.imageSource)return '';if(m.imageStatus==='generated_fallback')return '대체 이미지';if(m.imageSourceUrl)return '<a href="'+escapeHtml(m.imageSourceUrl)+'" target="_blank" rel="noopener">공개 이미지 출처</a>';return '공개 이미지'}
function selectedMountain(){const id=new URLSearchParams(location.search).get('mountain')||localStorage.getItem('dmc.lastMountain')||'bukhansan';return mountains.find(m=>m.id===id)||mountains[0]}
function goDashboard(id){localStorage.setItem('dmc.lastMountain',id);location.href='dashboard.html?mountain='+encodeURIComponent(id)}
window.goDashboard=goDashboard;
function selectedArchiveMountain(){const id=new URLSearchParams(location.search).get('mountain')||localStorage.getItem('dmc.lastMountain')||mountains[0]?.id;return mountains.find(m=>m.id===id)||mountains[0]}
function archiveDetailHtml(m){if(!m)return '<div class="empty">산을 선택하면 상세 대시보드가 표시됩니다.</div>';const f=m.facilities||{};const c=m.course||{};const source=m.imageStatus==='copyright_unverified_test'?'테스트 이미지':(m.imageSourceUrl?'공개 이미지':'이미지');return '<div class="detail-hero"><img src="'+escapeHtml(mountainImage(m))+'" alt="'+escapeHtml(m.imageAlt||m.name+' 이미지')+'"><span>'+source+'</span></div><div class="detail-title-row"><div><p class="eyebrow">선택한 산</p><h2>'+escapeHtml(m.name)+'</h2><p class="muted">'+escapeHtml(m.region)+' · '+escapeHtml(m.height||'')+'m · '+escapeHtml(m.level)+'</p></div><a class="btn primary" href="dashboard.html?mountain='+encodeURIComponent(m.id)+'">공유용 상세 열기</a></div><div class="status-strip"><div><strong>오늘 산행 상태</strong><span>날씨 API 연결 시 자동 갱신</span></div><div><strong>'+escapeHtml(m.time)+'</strong><span>예상 시간</span></div><div><strong>'+escapeHtml(m.distance)+'</strong><span>거리</span></div><div><strong>'+escapeHtml(m.elevation)+'</strong><span>누적고도</span></div></div><section class="mini-section"><h3>대표 코스 요약</h3><p class="muted">'+escapeHtml(m.summary||m.desc||'코스 정보 준비중')+'</p><div class="tags"><span class="tag">출발 '+escapeHtml(c.start||'대표 등산로 입구')+'</span><span class="tag">정상 '+escapeHtml(c.summit||m.name)+'</span><span class="tag">하산 '+escapeHtml(c.end||'하산지점 정보 준비중')+'</span></div></section><section class="mini-section"><h3>위치 정보</h3><div class="map-actions tight"><a class="map-brand kakao" href="dashboard.html?mountain='+encodeURIComponent(m.id)+'#location">↗ 카카오맵에서 보기</a><a class="map-brand naver" href="dashboard.html?mountain='+encodeURIComponent(m.id)+'#location">↗ 네이버지도에서 보기</a></div></section><section class="mini-section"><h3>편의시설</h3>'+facilityCardsHtml(m,true)+'</section><div class="detail-tabs"><button>코스</button><button>구간안내</button><button>준비물</button><button>주의사항</button><button>주변정보</button></div>'}
function renderArchiveDetail(id){const m=id?mountains.find(x=>x.id===id):selectedArchiveMountain();const box=$('[data-search-detail]');if(!box||!m)return;localStorage.setItem('dmc.lastMountain',m.id);box.innerHTML=archiveDetailHtml(m);$$('[data-open]').forEach(el=>el.classList.toggle('selected',el.dataset.open===m.id));}
function renderMountainList(list=mountains){const box=$('[data-mountain-list]');if(!box)return;const isSearchPage=!!$('[data-search-page]');const selectedId=(selectedArchiveMountain()||{}).id;const limited=isSearchPage?list.slice(0,80):list;const count=$('[data-result-count]');if(count)count.textContent=list.length+'개 산';box.innerHTML=limited.length?limited.map(m=>'<article class="item '+(isSearchPage?'search-item ':'')+(m.id===selectedId?'selected':'')+'"><div class="thumb" style="background-image:url(&quot;'+escapeHtml(mountainImage(m))+'&quot;)"></div><div><h3>'+escapeHtml(m.name)+'</h3><p class="muted">'+escapeHtml(m.region)+' · '+escapeHtml(m.level)+' · '+escapeHtml(m.time)+' · '+escapeHtml(m.distance)+' · '+escapeHtml(m.elevation)+'</p><div class="tags"><span class="tag">'+escapeHtml(m.difficultyOriginal||m.level)+'</span><span class="tag">'+escapeHtml(m.course?.summit||'정상')+'</span></div></div><a class="btn primary" href="dashboard.html?mountain='+encodeURIComponent(m.id)+'" data-open="'+escapeHtml(m.id)+'">상세 보기</a></article>').join(''):'<div class="empty">조건에 맞는 산이 없습니다.</div>';$$('[data-open]').forEach(b=>b.addEventListener('click',e=>{if($('[data-search-page]')){e.preventDefault();const id=b.dataset.open;history.pushState(null,'','archive.html?mountain='+encodeURIComponent(id));renderArchiveDetail(id);const detail=$('[data-search-detail]');if(detail&&matchMedia('(max-width: 980px)').matches)detail.scrollIntoView({behavior:'smooth',block:'start'});}else{goDashboard(b.dataset.open)}}));if(isSearchPage)renderArchiveDetail(selectedId)}
function applyFilters(){const q=($('[data-search-input]')?.value||'').trim().toLowerCase();const region=$('.filter-btn.active[data-region]')?.dataset.region||'전체';const level=$('.filter-btn.active[data-level]')?.dataset.level||'전체';let list=mountains.filter(m=>(region==='전체'||m.region===region)&&(level==='전체'||m.level===level)&&(!q||[m.name,m.region,m.level,m.desc,m.summary,m.course?.summit].join(' ').toLowerCase().includes(q)));renderMountainList(list)}
function setupArchive(){if(!$('[data-mountain-list]'))return;renderMountainList();$$('.filter-btn').forEach(btn=>btn.addEventListener('click',()=>{if(btn.dataset.theme){btn.classList.toggle('active');return}const group=btn.dataset.region?'data-region':'data-level';$$('.filter-btn['+group+']').forEach(b=>b.classList.remove('active'));btn.classList.add('active');applyFilters()}));$('[data-search-input]')?.addEventListener('input',applyFilters);window.addEventListener('popstate',()=>renderArchiveDetail())}

function setupClubBanner(){
  const record=$('[data-club-record]');
  const mountain=$('[data-club-mountain]');
  const leader=$('[data-club-leader]');
  if(record) record.addEventListener('click',()=>{location.href='mypage.html#records'});
  if(mountain) mountain.addEventListener('click',()=>goDashboard(mountain.dataset.clubMountain||'gwanaksan'));
  if(leader) leader.addEventListener('click',()=>{location.href='mypage.html#leader'});
}

function setupHomeSearch(){const form=$('[data-home-search]');if(!form)return;form.addEventListener('submit',e=>{e.preventDefault();const q=$('[data-home-query]').value.trim();location.href='archive.html'+(q?'?q='+encodeURIComponent(q):'')})}
async function renderWeather(m){const box=$('[data-weather]');if(!box)return;box.innerHTML='<p class="muted">실시간 날씨를 불러오는 중입니다.</p>';try{const url=`https://api.open-meteo.com/v1/forecast?latitude=${m.lat}&longitude=${m.lon}&current=temperature_2m,relative_humidity_2m,wind_speed_10m,uv_index,weather_code&timezone=Asia%2FSeoul`;const res=await fetch(url);if(!res.ok)throw new Error('weather');const data=await res.json();const c=data.current;box.innerHTML=`<div class="stats"><div class="stat"><strong>${Math.round(c.temperature_2m)}°C</strong><span class="muted">기온</span></div><div class="stat"><strong>${c.relative_humidity_2m}%</strong><span class="muted">습도</span></div><div class="stat"><strong>${Math.round(c.wind_speed_10m)}km/h</strong><span class="muted">바람</span></div></div><p class="muted">Open-Meteo 무료 API 기준 · UV ${c.uv_index ?? '정보 없음'}</p>`}catch(e){box.innerHTML='<p class="note">날씨 API를 불러오지 못했습니다. GitHub Pages에 올린 뒤 네트워크가 허용되면 자동으로 다시 동작합니다.</p>'}}
function renderDashboard(){if(!$('[data-dashboard]'))return;const m=selectedMountain();document.title=m.name+' | 딕소톤 마운틴 클럽';$('[data-m-title]').textContent=m.name;$('[data-m-desc]').textContent=m.desc;const photo=$('[data-m-photo]');if(photo){photo.src=mountainImage(m);photo.alt=m.imageAlt||m.name+' 산 이미지'}const credit=$('[data-image-credit]');if(credit){credit.innerHTML=imageCredit(m)}$('[data-m-spec]').innerHTML='<li>지역: '+escapeHtml(m.region)+'</li><li>난이도: '+escapeHtml(m.level)+'</li><li>예상 소요 시간: '+escapeHtml(m.time)+'</li><li>왕복 거리: '+escapeHtml(m.distance)+'</li><li>누적 고도: '+escapeHtml(m.elevation)+'</li><li>좌표: '+Number(m.lat).toFixed(5)+', '+Number(m.lon).toFixed(5)+'</li><li>좌표 출처: '+(m.coordinateSource==='openstreetmap_nominatim_peak'||m.coordinateSource==='openstreetmap_nominatim_peak_name_disambiguated'?'OpenStreetMap':String(m.coordinateSource||'').startsWith('wikidata')?'Wikidata':'공개 데이터')+'</li>';$('[data-map]').src=`https://www.openstreetmap.org/export/embed.html?bbox=${m.lon-0.04}%2C${m.lat-0.03}%2C${m.lon+0.04}%2C${m.lat+0.03}&layer=mapnik&marker=${m.lat}%2C${m.lon}`;renderLocationInfo(m);renderFacilities(m);renderRecommended(m);renderCourseSummary(m);$('[data-save]').textContent=isSaved(m.id)?'저장 해제':'저장하기';$('[data-save]').onclick=()=>toggleSave(m.id);$('[data-gpx]').onclick=()=>downloadGpx(m);renderWeather(m);renderReviews(m.id)}

function renderLocationInfo(m){const start=$('[data-route-start]');const end=$('[data-route-end]');if(start)start.textContent=m.course?.start&&m.course.start!=='출발지 정보 준비중'?m.course.start:'대표 등산로 입구';if(end)end.textContent=m.course?.end&&m.course.end!=='하산지점 정보 준비중'?m.course.end:(m.course?.summit||m.name+' 정상');$('[data-map-placeholder]').forEach(btn=>{btn.onclick=()=>{btn.classList.add('tapped');setTimeout(()=>btn.classList.remove('tapped'),220)}})}

function facilityValue(raw, fallback){const value=String(raw||'').trim();if(!value||value==='확인 필요'||value==='정보 준비중')return fallback;return value}
function facilityTone(value){return /없음|불가|운영 안|폐쇄|없/.test(value)?'bad':(/확인|준비/.test(value)?'warn':'good')}
function facilityCardsHtml(m, compact=false){const f=m.facilities||{};const cards=[{icon:'🚻',label:'화장실',value:facilityValue(f.toilet,'있음')},{icon:'🏪',label:'편의점',value:facilityValue(f.convenienceStore,'입구 5분')},{icon:'🥾',label:'먼지털이',value:facilityValue(f.dustCleaner,'하산지점')},{icon:'🚙',label:'주차',value:facilityValue(f.parking,'가능')},{icon:'🚌',label:'버스정류장',value:facilityValue(f.busStop,'300m')},{icon:'💧',label:'식수',value:facilityValue(f.water,'없음')}];return '<div class="facility-card-grid '+(compact?'compact':'')+'">'+cards.map(card=>'<div class="facility-card '+facilityTone(card.value)+'"><div class="facility-icon" aria-hidden="true">'+card.icon+'</div><span>'+escapeHtml(card.label)+'</span><strong>'+escapeHtml(card.value)+'</strong></div>').join('')+'</div>'}

function renderFacilities(m){const box=$('[data-facilities]');if(!box)return;box.innerHTML=facilityCardsHtml(m)}
function renderRecommended(m){const box=$('[data-recommended]');if(!box)return;const list=Array.isArray(m.recommendedFor)?m.recommendedFor:[];box.innerHTML=list.length?list.map(x=>'<li>'+x+'</li>').join(''):'<li>정보 준비중</li>'}
function renderCourseSummary(m){const box=$('[data-course-summary]');if(!box)return;const c=m.course||{};box.innerHTML='<p class="muted">'+(m.summary||m.desc||'코스 요약 준비중')+'</p><div class="tags"><span class="tag">출발 '+(c.start||'-')+'</span><span class="tag">정상 '+(c.summit||'-')+'</span><span class="tag">하산 '+(c.end||'-')+'</span></div>'}

function downloadGpx(m){const gpx=`<?xml version="1.0" encoding="UTF-8"?><gpx version="1.1" creator="딕소톤 마운틴 클럽"><wpt lat="${m.lat}" lon="${m.lon}"><name>${m.name}</name></wpt><trk><name>${m.name} sample route</name><trkseg><trkpt lat="${m.lat-0.01}" lon="${m.lon-0.01}"></trkpt><trkpt lat="${m.lat}" lon="${m.lon}"></trkpt><trkpt lat="${m.lat+0.01}" lon="${m.lon+0.01}"></trkpt></trkseg></trk></gpx>`;const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([gpx],{type:'application/gpx+xml'}));a.download=m.id+'.gpx';a.click();setTimeout(()=>URL.revokeObjectURL(a.href),1000)}
function reviewKey(id){return 'dmc.reviews.'+id}function getReviews(id){return JSON.parse(localStorage.getItem(reviewKey(id))||'[]')}function setReviews(id,v){localStorage.setItem(reviewKey(id),JSON.stringify(v))}
function renderReviews(id){const list=$('[data-review-list]');if(!list)return;const reviews=getReviews(id);list.innerHTML=reviews.length?reviews.map(r=>`<div class="review"><strong>${r.name}</strong><p class="muted">${r.text}</p></div>`).join(''):'<div class="empty">아직 저장된 후기가 없습니다. 첫 후기를 남겨보세요.</div>';const form=$('[data-review-form]');form.onsubmit=e=>{e.preventDefault();const name=$('[data-review-name]').value.trim()||'익명 회원';const text=$('[data-review-text]').value.trim();if(!text){toast('후기를 입력해주세요');return}setReviews(id,[{name,text,date:new Date().toISOString()},...getReviews(id)]);$('[data-review-text]').value='';toast('후기를 저장했습니다');renderReviews(id)}}
function renderMyPage(){if(!$('[data-my-page]'))return;const saved=getSaved().map(id=>mountains.find(m=>m.id===id)).filter(Boolean);$('[data-saved-list]').innerHTML=saved.length?saved.map(m=>`<li><button class="btn ghost" data-open="${m.id}">${m.name}</button></li>`).join(''):'<li class="muted">저장한 산이 없습니다.</li>';$$('[data-open]').forEach(b=>b.addEventListener('click',()=>goDashboard(b.dataset.open)));let reviewCount=mountains.reduce((n,m)=>n+getReviews(m.id).length,0);$('[data-review-count]').textContent=reviewCount;$('[data-saved-count]').textContent=saved.length}
function renderDynamic(){updateSavedCounts();renderDashboard();renderMyPage()}
document.addEventListener('DOMContentLoaded',async()=>{await loadMountains();const params=new URLSearchParams(location.search);const q=params.get('q');if(q&&$('[data-search-input]'))$('[data-search-input]').value=q;setupHomeSearch();setupClubBanner();setupArchive();if(q)applyFilters();renderDynamic()});
